<?php
namespace App\Http\Controllers\Api;
use App\Enums\RecoveryStatus;use App\Http\Controllers\Controller;use App\Models\LoanRecoveryCase;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;use Illuminate\Validation\Rule;
class LoanRecoveryController extends Controller{public function index():JsonResponse{return response()->json(LoanRecoveryCase::query()->with(['actions'])->latest('opened_at')->paginate());}public function show(LoanRecoveryCase $recoveryCase):JsonResponse{return response()->json($recoveryCase->load('actions'));}public function update(Request $request,LoanRecoveryCase $recoveryCase):JsonResponse{$d=$request->validate(['status'=>['required',Rule::enum(RecoveryStatus::class)],'assigned_to'=>['nullable','ulid'],'promise_date'=>['nullable','date'],'promise_amount_minor'=>['nullable','integer','min:1']]);$d['resolved_at']=in_array($d['status'],[RecoveryStatus::Resolved->value,RecoveryStatus::WrittenOff->value],true)?now():null;$recoveryCase->update($d);return response()->json($recoveryCase->refresh());}public function action(Request $request,LoanRecoveryCase $recoveryCase):JsonResponse{$d=$request->validate(['type'=>['required','in:call,email,sms,visit,demand_notice,promise_to_pay,guarantor_contact,legal_referral,write_off_review,other'],'notes'=>['required','string','max:5000'],'next_action_at'=>['nullable','date'],'expense_minor'=>['sometimes','integer','min:0']]);$action=$recoveryCase->actions()->create([...$d,'performed_by'=>Auth::id(),'performed_at'=>now()]);$expense=(int)($d['expense_minor']??0);if($expense>0){$installment=$recoveryCase->loan()->firstOrFail()->installments()->where('status',\App\Enums\InstallmentStatus::Overdue->value)->orderBy('due_date')->firstOrFail();$installment->increment('recovery_expenses_due_minor',$expense);$installment->loan->increment('outstanding_minor',$expense);$recoveryCase->increment('arrears_minor',$expense);}return response()->json($action,201);}}
